    ADD CONSTRAINT pph_changed_by_fkey FOREIGN KEY (changed_by)
    REFERENCES public.app_users (username) MATCH SIMPLE
    ON UPDATE CASCADE
    ON DELETE SET NULL;

ALTER TABLE IF EXISTS public.product_prices
    ADD CONSTRAINT product_prices_area_id_fkey FOREIGN KEY (area_id)
    REFERENCES public.area_overrides (area_id) MATCH SIMPLE
    ON UPDATE NO ACTION
    ON DELETE CASCADE;
CREATE INDEX IF NOT EXISTS idx_pp_area_id
    ON public.product_prices(area_id);

ALTER TABLE IF EXISTS public.product_prices
    ADD CONSTRAINT product_prices_product_id_fkey FOREIGN KEY (product_id)
    REFERENCES public.products (id) MATCH SIMPLE
    ON UPDATE NO ACTION
    ON DELETE CASCADE;
CREATE INDEX IF NOT EXISTS idx_pp_product_id
    ON public.product_prices(product_id);

